kernel = Kernel()

# Add Vex filter to trace plugin chain failures
def chain_error_detector(func_result):
    if hasattr(func_result, 'error') and func_result.error:
        # Check if error cascades from previous plugin
        if 'SKFunctionExecutionError' in str(func_result.error):
            print(f'🚨 CASCADE ERROR: {func_result.error}')
            return {'status': 'error', 'chain_broken': True}
    return {'status': 'ok'}

# Register as result filter
kernel.filters.add_result_filter(chain_error_detector)
