import { SequentialPlanner } from '@semantic-kernel/agents';

const kernel = Kernel.create();

function validatePlan(plan: any[]) {
  const functionNames = kernel.functions.list().map(f => f.name);
  const invalidFunctions = plan
    .filter((step: any) => !functionNames.includes(step.function));

  if (invalidFunctions.length > 0) {
    console.error('🚨 INVALID PLAN:', invalidFunctions);
    return false;
  }
  return true;
}

const planner = SequentialPlanner.fromKernel(kernel);
const plan = await planner.createPlan(['task']);
validatePlan(plan);
