from semantic_kernel import KernelFunction
from pydantic import BaseModel, ValidationError
from typing import Any

def validate_plugin_input(input_schema: type[BaseModel]):
    def decorator(func: KernelFunction):
        async def wrapper(*args, context: Any, **kwargs):
            try:
                validated = input_schema(**context.variables)
                return await func(*args, context=context, **kwargs)
            except ValidationError as e:
                context.variables['error'] = f'Input validation failed: {e}'
                return None
        return wrapper
    return decorator

# Usage
