import { Kernel } from '@semantic-kernel/core';
import { SequentialPlanner } from '@semantic-kernel/agents';

async function safePlan(kernel: Kernel, goal: string, maxRetries = 3): Promise<any> {
  const planner = SequentialPlanner.fromKernel(kernel);

  for (let i = 0; i < maxRetries; i++) {
    try {
      const plan = await planner.createPlan([goal]);
      if (await validatePlan(plan, kernel)) {
        return plan;
      }
    } catch (error) {
      console.warn(`Plan attempt ${i + 1} failed:`, error);
    }
  }

  // Fallback to single function
  return [{ function: 'default_handler', input: goal }];
}
